const express = require('express');
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);

module.exports = app;

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    throw new BadRequestError('Name is required');
  }
  const project = service.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { generateId } = require('../../lib/id');

let projects = [];

function getAllProjects() {
  return projects;
}

function createProject(name) {
  const project = { id: generateId(), name, members: [], tasks: [] };
  projects.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    throw new BadRequestError('UserId and role are required');
  }
  const member = service.addMember(projectId, userId, role);
  res.status(201).json({ member });
});

module.exports = router;

const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

function addMember(projectId, userId, role) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  const member = { id: generateId(), userId, role };
  project.members.push(member);
  return member;
}

module.exports = {
  addMember,
};

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  let tasks = service.getAllTasks(projectId);
  if (req.query.status === 'done') {
    tasks = tasks.filter(task => task.status === 'done');
  }
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title || typeof title !== 'string' || title.trim() === '') {
    throw new BadRequestError('Title is required');
  }
  const task = service.createTask(projectId, title);
  res.status(201).json({ task });
});

module.exports = router;

const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

function getAllTasks(projectId) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  return project.tasks;
}

function createTask(projectId, title) {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  const task = { id: generateId(), title, status: 'pending' };
  project.tasks.push(task);
  return task;
}

module.exports = {
  getAllTasks,
  createTask,
};

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const taskId = req.params.taskId;
  const comments = service.getAllComments(taskId);
  res.json({ comments });
});

router.post('/', (req, res) => {
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message || typeof message !== 'string' || message.trim() === '') {
    throw new BadRequestError('Message is required');
  }
  const comment = service.addComment(taskId, message);
  res.status(201).json({ comment });
});

module.exports = router;

const { generateId } = require('../../lib/id');
tasksService = require('../tasks/service');

function getAllComments(taskId) {
  const task = tasksService.getAllTasks().flat().find(t => t.id === taskId);
  if (!task) {
    throw new Error('Task not found');
  }
  return task.comments || [];
}

function addComment(taskId, message) {
  const task = tasksService.getAllTasks().flat().find(t => t.id === taskId);
  if (!task) {
    throw new Error('Task not found');
  }
  const comment = { id: generateId(), message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
}

module.exports = {
  getAllComments,
  addComment,
};
